"""Fourth batch: ~460 more examples to reach ~800 total."""
import json, os

OUTPUT_DIR = os.path.join(os.path.dirname(__file__), "raw")
SYS = "You are a ransomware forensic analyst with deep expertise in Windows internals and incident response."
AT = "2026-03-17T11:00:00Z"
GM = "claude-opus-4-6"

def mk(src, url, sec, et, topics, pid, q, a):
    return {"messages":[{"role":"system","content":SYS},{"role":"user","content":q},{"role":"assistant","content":a}],
            "metadata":{"source":src,"source_url":url,"source_section":sec,"example_type":et,"topics":topics,
                        "generation_prompt_id":pid,"generated_at":AT,"generator_model":GM,"quality_score":None}}

def append_jsonl(fname, examples):
    path = os.path.join(OUTPUT_DIR, fname)
    with open(path, "a") as f:
        for ex in examples:
            f.write(json.dumps(ex, ensure_ascii=False) + "\n")
    return len(examples)

def cisa_b4():
    S,U="cisa_stopransomware","https://www.cisa.gov/stopransomware/ransomware-guide"
    P,I,X="cisa_qa_v4","cisa_instruction_v4","cisa_passage_v4"
    R=[]
    # 76 examples for CISA
    D=[
("Forensic Investigation","qa",["event_4625","brute_force"],P,"How do you analyze Event ID 4625 patterns to detect brute-force attacks targeting RDP?","Event ID 4625 (failed logon) records: target account name, source network address, logon type, failure reason (sub-status), and timestamp. For RDP brute-force detection: filter for Logon Type 10 (RemoteInteractive) with sub-status 0xC000006A (bad password) or 0xC0000064 (user does not exist). Key patterns include: multiple failures from the same source IP targeting different accounts (password spraying); multiple failures targeting the same account from different IPs (distributed brute-force); and high-frequency failures from a single IP (traditional brute-force). Create SIEM alerts for: more than 10 failed logons from a single external IP within 5 minutes; more than 5 failed logons to the same account within 10 minutes from external sources; and any successful logon (4624 Type 10) preceded by multiple failures from the same source. Cross-reference source IPs against threat intelligence feeds and geolocation data. Event ID 4625 with sub-status 0xC0000072 indicates the account is disabled but the password was correct, suggesting the attacker has valid credentials."),
("Forensic Investigation","qa",["event_4697","audit_service"],P,"What does Event ID 4697 reveal about service installation that Event ID 7045 does not?","Event ID 4697 (Security Audit: A service was installed in the system) records the service installation from a security auditing perspective, including the account that installed the service and the account context under which the service will run. Event ID 7045 (System log: New service installed) records the technical details: service name, service file name, service type, and start type. Together they provide: the user account responsible for installing the service (4697), the service binary path (7045), the service account context (4697), and the startup configuration (7045). For ransomware investigation: PsExec creates the PSEXESVC service (7045 shows the binary path; 4697 shows which account installed it); Cobalt Strike services often use random names with cmd.exe or PowerShell payloads in the binary path; and BYOVD driver installations appear as kernel driver service types. Enable both event sources: 4697 requires 'Audit Security System Extension' in Advanced Audit Policy; 7045 is logged by default in the System log."),
("Prevention Best Practices","qa",["kerberos_hardening","authentication"],P,"What Kerberos authentication hardening measures help prevent ransomware credential attacks?","Kerberos hardening targets the specific attack techniques ransomware operators use. Against Kerberoasting: remove SPNs from service accounts where they are not needed; use Group Managed Service Accounts (gMSAs) with 120-character auto-rotating passwords; set service account passwords to 25+ characters; and monitor Event ID 4769 for RC4-encrypted ticket requests (Encryption Type 0x17). Against AS-REP Roasting: ensure all accounts have Kerberos pre-authentication enabled (check for DONT_REQUIRE_PREAUTH flag). Against Golden Ticket: reset the KRBTGT password every 180 days as a proactive measure; implement Azure AD Kerberos for cloud-integrated environments; and monitor for TGT usage from unexpected sources. Against Pass-the-Ticket: implement Credential Guard to protect Kerberos tickets in memory; use Protected Users security group for sensitive accounts (prevents NTLM authentication and caches credentials for shorter periods). Against unconstrained delegation: audit all systems with unconstrained delegation configured and convert to constrained delegation or resource-based constrained delegation where possible."),
("Response Checklist","instruction",["mass_password_reset","credential_recovery"],I,"Describe the proper procedure for a domain-wide password reset after a ransomware incident.","Domain-wide password reset requires careful planning to avoid self-inflicted outages. Phase 1 (Preparation): document all service accounts and their dependencies; coordinate with application owners; ensure LAPS is deployed for local admin passwords; prepare communication templates for end users; and schedule the reset during a maintenance window. Phase 2 (Privileged accounts first): reset all Domain Admin, Enterprise Admin, and Schema Admin passwords; reset the KRBTGT password twice with a 12+ hour gap between resets to allow replication while invalidating all existing Kerberos tickets; reset DSRM passwords on all domain controllers; and reset all Tier 0 service account passwords, coordinating with dependent applications. Phase 3 (Service accounts): reset all service accounts systematically, updating the password in both AD and the application configuration simultaneously; use gMSAs where possible to automate this going forward; and test each application after its service account password is changed. Phase 4 (User accounts): force password reset for all user accounts at next logon; communicate the requirement to users with instructions for new password requirements; and have help desk staff prepared for increased call volume. Phase 5 (Verification): confirm all accounts have been reset by checking the pwdLastSet attribute; verify no accounts were missed; and monitor for authentication failures indicating applications still using old credentials."),
("Prevention Best Practices","qa",["wdac_deployment","application_control"],P,"How should Windows Defender Application Control (WDAC) be deployed for ransomware prevention?","WDAC provides kernel-enforced application control that ransomware cannot bypass from user mode. Deployment approach: (1) Audit mode first: deploy WDAC policies in audit mode (Event ID 3076 in CodeIntegrity-Operational log) to identify all executables that would be blocked; run for 2-4 weeks to capture normal operational patterns. (2) Policy creation: create a base policy allowing Microsoft-signed binaries, then supplement with rules for approved business applications identified during audit; use publisher rules for signed software and hash rules for unsigned necessary applications. (3) Managed installer: configure SCCM/Intune as a managed installer so applications deployed through the management platform are automatically trusted. (4) Supplemental policies: use supplemental policies for department-specific applications to keep the base policy clean. (5) Enforcement: gradually move to enforcement mode, starting with a pilot group of systems and expanding as confidence grows. For ransomware prevention specifically: WDAC blocks execution of unknown binaries from any location, preventing ransomware payloads, lateral movement tools, and credential theft utilities from executing even if they reach the endpoint."),
("Forensic Investigation","qa",["shimcache_timeline","execution_evidence"],P,"How do you build a program execution timeline using Shimcache, Amcache, Prefetch, and UserAssist together?","Each artifact provides different execution metadata, and combining them creates the most complete picture. Shimcache: provides file path and last modification timestamp; indicates file system access (not necessarily execution on Win10+); entries ordered by most recent access. Amcache: provides file path, SHA1 hash, PE metadata, and first execution timestamp; confirms actual execution. Prefetch: provides executable name, run count, up to 8 last execution timestamps, and files accessed during first 10 seconds of execution. UserAssist: provides GUI-launched program path (ROT13 encoded), run count, last execution timestamp, and focus time. Correlation methodology: for a suspected attacker tool, check all four sources: Shimcache confirms the file existed on the system; Amcache SHA1 hash enables VirusTotal lookup for malware identification; Prefetch run count and timestamps show how many times and when the tool was used; and UserAssist indicates whether it was launched through the GUI (suggesting RDP-based interactive use). Discrepancies are informative: a tool in Shimcache/Amcache but not Prefetch may have been executed on a system with Prefetch disabled (servers); a tool in Prefetch but not UserAssist was launched from command line rather than GUI."),
("Prevention Best Practices","qa",["dns_sinkholing","containment"],P,"How should organizations implement DNS sinkholing for ransomware containment?","DNS sinkholing redirects malicious domain queries to a controlled IP address, cutting off C2 communication. Implementation: configure your internal DNS resolver to return a sinkhole IP (typically an internal web server logging all connection attempts) for known malicious domains. Sources for sinkhole lists: CISA's automated indicator sharing feed; commercial threat intelligence DNS feeds; open-source blocklists (abuse.ch URLhaus, SANS ISC); and organization-specific IOCs from active incidents. For active ransomware containment: immediately add all C2 domains identified in beacon configurations to the DNS sinkhole; this severs the attacker's communication channel for beacon-based operations. The sinkhole web server should log all connection attempts, providing: a list of all systems still trying to reach the C2 (identifying additional compromised hosts); connection frequency revealing the beacon sleep interval; and confirmation that containment is effective when connections cease after system cleanup. Limitations: DNS sinkholing does not work against: hardcoded IP addresses in malware; DNS-over-HTTPS configured to use external resolvers; and malware using direct IP communication. Complement sinkholing with firewall blocks on the C2 IP addresses."),
("Forensic Investigation","qa",["wmi_repository","persistence_forensics"],P,"How do you forensically analyze the WMI repository for persistence mechanisms?","The WMI repository is stored at C:\\Windows\\System32\\wbem\\Repository\\ and contains: OBJECTS.DATA (object definitions), INDEX.BTR (index), and MAPPING*.MAP files. For forensic analysis: use PyWMIPersistenceFinder or python-cim to parse OBJECTS.DATA and extract all event subscriptions (filters, consumers, and bindings). Malicious WMI persistence uses three components: an EventFilter defining the trigger condition (e.g., __InstanceModificationEvent for system startup, or __TimerEvent for timed execution); an EventConsumer defining the action (CommandLineEventConsumer for executing commands, or ActiveScriptEventConsumer for running scripts); and a FilterToConsumerBinding linking them. Search for: CommandLineEventConsumer entries with PowerShell, cmd.exe, or encoded commands; ActiveScriptEventConsumer entries with VBScript or JScript code; unusual trigger conditions targeting system events; and consumer actions that download or execute remote content. Timeline: WMI objects have embedded timestamps that reveal when the persistence was established. Even deleted WMI subscriptions leave artifacts in the repository that can be recovered through dead object analysis."),
("Prevention Best Practices","qa",["certificate_pinning","tls_security"],P,"How can TLS certificate pinning and inspection help detect ransomware C2 traffic?","TLS inspection deploys a trusted proxy that decrypts, inspects, and re-encrypts HTTPS traffic. For ransomware detection: inspect for Cobalt Strike beacon traffic patterns (specific URI paths, HTTP headers matching malleable profiles); detect encoded PowerShell commands in HTTP POST bodies; identify data exfiltration payloads (base64-encoded data, large file uploads); and block connections to known C2 domains/IPs. Certificate pinning on the endpoint side: implement certificate transparency monitoring to detect suspicious certificates issued for your domains (potential adversary-in-the-middle for credential theft). For corporate environments: deploy the proxy CA certificate to all managed endpoints; configure bypass rules for sensitive applications (banking, healthcare portals); and log all decrypted traffic metadata for forensic analysis. Detection rules on decrypted traffic: Cobalt Strike default profiles with specific User-Agent strings; Rclone MEGA API calls; encoded PowerShell download cradles; and suspicious file uploads to cloud storage services. Limitation: some malware uses certificate pinning to prevent inspection; this manifests as connection failures through the proxy, which itself becomes a detection signal."),
("Response Checklist","qa",["recovery_prioritization","business_impact"],P,"How should organizations prioritize system recovery after ransomware encryption?","Recovery prioritization should follow the organization's Business Impact Analysis (BIA) and Recovery Time Objectives (RTOs). Tier 1 (restore within 4 hours): Active Directory domain controllers and DNS (all other recovery depends on identity infrastructure); core network infrastructure (DHCP, routing); and the SIEM/monitoring platform to maintain visibility during recovery. Tier 2 (restore within 24 hours): email infrastructure (enables internal and external communication); critical business applications identified in the BIA (ERP, patient care systems, financial systems); and backup infrastructure if it was compromised. Tier 3 (restore within 72 hours): file servers (starting with the most business-critical shares); secondary business applications; and web-facing services. Tier 4 (restore within 1-2 weeks): end-user workstations (rebuild from golden images rather than restoring from backup); non-critical applications; and development/test environments. Recovery approach: restore from the most recent clean backup that predates the intrusion (not just the encryption); rebuild endpoints from golden images with current patches; implement additional monitoring and hardening before reconnecting each system to the network; and verify each restored system is clean before allowing it to communicate with other recovered systems."),
("Forensic Investigation","qa",["sysmon_config_analysis","detection_gaps"],P,"How do you assess whether the existing Sysmon configuration was adequate for investigating a ransomware incident?","Post-incident Sysmon configuration assessment identifies detection gaps. Review the current Sysmon configuration: export using 'sysmon -c' on a representative system; check the configuration XML for which events are enabled and what filters are applied. Common gaps that impair ransomware investigation: Event ID 1 (Process Creation) filtered too aggressively, missing attacker tool execution from unexpected paths; Event ID 3 (Network Connection) disabled entirely or filtered to exclude outbound connections, missing C2 beacon traffic; Event ID 7 (Image Loaded) not enabled, preventing DLL side-loading detection; Event ID 8 (CreateRemoteThread) not enabled, missing process injection by Cobalt Strike; Event ID 10 (ProcessAccess) not filtering for LSASS access, missing credential dumping; Event ID 17/18 (Pipe events) not enabled, missing Cobalt Strike named pipe communication; and Event ID 22 (DNS Query) not enabled, missing C2 domain resolution. Improvement recommendations: compare the current config against the SwiftOnSecurity and Olaf Hartong modular configs; add missing events critical for ransomware detection; tune existing filters to reduce noise while maintaining detection coverage; and validate the updated config using Atomic Red Team tests before deploying."),
("Forensic Investigation","qa",["shellbag_analysis","directory_browsing"],P,"How do ShellBag artifacts help reconstruct attacker activity during an RDP-based ransomware intrusion?","ShellBags record every folder accessed through Windows Explorer, persisting indefinitely in the UsrClass.dat registry hive. During RDP-based intrusions, attackers use Explorer to browse the file system, creating ShellBag entries that reveal their objectives. Key analysis: ShellBags for network paths (\\\\server\\share\\path) show which file servers and shares the attacker explored, providing the data reconnaissance footprint; ShellBags with timestamps correlating to the attack timeline identify attacker-accessed directories; entries for removable media or mapped drives indicate data staging locations; and entries for system directories (C:\\Windows\\System32, C:\\ProgramData) suggest tool deployment locations. Cross-reference with: RDP session times (Event ID 4624 Type 10) to correlate directory browsing with specific logon sessions; file server audit logs (Event ID 5145) to verify which files within those directories were actually accessed; and LNK files/Jump Lists to identify specific files opened from the browsed directories. ShellBag evidence survives ransomware encryption of the user profile files since UsrClass.dat is typically not encrypted."),
("Prevention Best Practices","qa",["vulnerability_scanning","asset_management"],P,"How should vulnerability scanning be integrated with ransomware prevention programs?","Vulnerability scanning specifically for ransomware prevention should prioritize: internet-facing attack surface as the highest priority (weekly scans of all external services); authenticated scanning of internal systems focusing on critical vulnerabilities exploited by ransomware groups (monthly); configuration compliance scanning for: RDP exposure, SMB settings, PowerShell configuration, and local admin password reuse. Priority vulnerability categories: CISA Known Exploited Vulnerabilities (KEV) catalog entries with a 14-day remediation SLA; VPN/remote access appliance vulnerabilities (Fortinet, Ivanti, Citrix, Palo Alto) with a 48-hour SLA; Microsoft Exchange vulnerabilities with a 7-day SLA; and Active Directory-related vulnerabilities (Zerologon, PrintNightmare, PetitPotam) with a 7-day SLA. Scanner configuration: enable credentialed scanning for accurate results; include: missing patches, weak configurations, exposed services, default credentials, and certificate issues. Output integration: feed scan results into a risk-based prioritization system that considers: CVSS score, active exploitation status, internet-facing exposure, and business criticality of the affected system."),
("Prevention Best Practices","qa",["credential_monitoring","breach_detection"],P,"How should organizations monitor for compromised credentials to prevent ransomware initial access?","Credential monitoring addresses the growing ransomware initial access vector of purchased or stolen credentials. Integration approaches: implement Azure AD Password Protection to block commonly breached passwords during password changes; integrate the Have I Been Pwned API for checking employee credentials against known breaches; deploy commercial dark web monitoring (SpyCloud, Recorded Future, Flare) that searches underground forums and infostealer logs for corporate credentials. Infostealer monitoring: monitor for corporate email addresses appearing in Raccoon, Vidar, RedLine, and other infostealer marketplaces; search for corporate domain names in credential dump listings; and check for VPN, RDP, and email credentials specifically. Response procedures: immediately reset any credential found in a breach database; force MFA enrollment or re-enrollment for affected accounts; investigate the source system for active infostealer infection; and review authentication logs for the affected account for any unauthorized access between the breach date and the reset. Proactive measures: enforce unique passwords through technical controls; prohibit password reuse between corporate and personal accounts through policy; and conduct regular credential audits matching employee passwords against breach databases."),
("Prevention Best Practices","qa",["security_operations","24x7_monitoring"],P,"What is the business case for 24/7 SOC monitoring to prevent ransomware damage?","The business case for 24/7 monitoring rests on ransomware operators' deliberate targeting of off-hours windows. Data shows: ransomware deployment occurs disproportionately on Friday evenings, weekends, and holidays when organizations have reduced staffing; the median time from detection to containment drops from 18 hours (business-hours-only SOC) to 1 hour (24/7 SOC); and the median number of encrypted systems in contained incidents drops from hundreds to single digits when containment occurs within 30 minutes of detection. Cost-benefit analysis: the average ransomware incident costs $4.5M (IBM Cost of a Data Breach 2024); 24/7 SOC operations via managed detection and response (MDR) cost $100K-$500K annually depending on environment size; this represents a 10:1 to 45:1 ROI if one incident is prevented or significantly reduced annually. Implementation options: internal 24/7 SOC with three shifts of analysts; outsourced MDR service providing 24/7 monitoring and initial response; or hybrid model with internal analysts during business hours and MDR after-hours coverage. Key: the SOC must have authority to take containment actions (network isolation, account disabling) without waiting for management approval during off-hours."),
("Forensic Investigation","qa",["event_id_4768","kerberos_auth"],P,"How do you use Event ID 4768 (Kerberos TGT Request) for ransomware investigation?","Event ID 4768 records Ticket Granting Ticket requests and provides key authentication intelligence. Key fields: account name requesting the TGT, source IP address, pre-authentication type (indicates authentication method), result code (success or specific failure), and encryption type. For ransomware investigation: AS-REP Roasting detection: Event ID 4768 with pre-authentication type 0 and encryption type 0x17 (RC4) indicates an AS-REP Roast attempt against accounts with pre-authentication disabled. Pass-the-Hash detection: TGT requests with NTLM pre-authentication (type 2) from unexpected source IPs may indicate PTH using harvested NTLM hashes. Account compromise timing: the first TGT request from an unusual IP address for a compromised account establishes when the attacker began using those credentials. Brute-force detection: failed TGT requests (result code 0x18 - wrong password) from unusual sources. Domain controller health: TGT requests should originate from the domain where the account resides; cross-domain TGT requests may indicate trust exploitation."),
("Forensic Investigation","qa",["event_log_tampering","anti_forensics_detection"],P,"How do you detect selective event log tampering where individual events are deleted rather than the entire log being cleared?","Selective event log deletion is more sophisticated than clearing the entire log (which generates Event ID 1102). Detection methods: Record ID gap analysis: each event in the Security log has a sequential Event Record ID; gaps in the sequence indicate deleted events. Tools like EvtxECmd export Record IDs, enabling gap detection through simple spreadsheet analysis. Log file size anomaly: if events are deleted but the log file size does not decrease proportionally, the deletion may have been done with a tool that zeros records without reclaiming space. Journal analysis: the NTFS $UsnJrnl records modifications to the .evtx log files; log file writes that do not correlate with expected log generation patterns may indicate tampering. Cross-source validation: compare events that should exist in multiple sources (e.g., a Type 10 logon should appear in both Security Event ID 4624 and TerminalServices Event ID 21); if one source has the event and the other does not, selective deletion may have occurred. Tool detection: tools like Danderspritz (leaked NSA tool) and Phant0m use specific techniques to delete events; detect their execution artifacts in process creation logs."),
("Response Checklist","qa",["supply_chain_notification","third_party"],P,"How should organizations notify supply chain partners and customers during a ransomware incident?","Supply chain notification requires balancing transparency with legal protection. Assessment first: determine which partners may be affected (shared network connections, data shared with partners, services provided to customers); assess whether partner data was accessed or exfiltrated. Notification timing: engage legal counsel before any notification to protect privileged communications; notify partners with direct network connections immediately so they can monitor their own environments for compromise; notify customers as required by contracts and regulations. Content: provide factual information about: what happened (confirmed facts only), when it occurred, what data may be affected, what steps you are taking, and what actions partners should take. Communication method: use out-of-band communication (phone, personal email) since corporate email may be compromised and the attacker may be monitoring communications; designate a single point of contact for partner inquiries. For service providers: notify downstream customers who receive services that are disrupted; provide estimated restoration timelines; and offer alternative service arrangements if available. Post-incident: share sanitized IOCs with partners so they can check their own environments; conduct joint review of interconnection security; and update contracts to include enhanced security requirements."),
("Forensic Investigation","qa",["evidence_correlation","multi_source"],P,"How do you correlate evidence across multiple forensic artifact sources to build a comprehensive attack narrative?","Multi-source correlation transforms individual artifacts into a coherent attack story. Methodology: (1) Timestamp normalization: convert all timestamps to UTC and note the timezone of each source system; verify system clock accuracy against NTP logs. (2) Pivot on known facts: start with confirmed events (ransomware execution timestamp from Prefetch, ransom note creation from $MFT) and expand outward. (3) Cross-source validation: for each significant event, verify it in at least two independent sources (e.g., lateral movement should appear in both authentication logs and network connection logs). (4) Fill gaps: when one source lacks coverage (e.g., event logs cleared), use alternative sources (forwarded events, Shimcache, SRUM network data). (5) Contradiction resolution: when sources conflict (different timestamps for the same event), determine which source is more reliable based on the artifact type and collection method. Common correlations: process creation (Event ID 4688) with network connections (Sysmon Event ID 3) linking execution to C2 communication; file creation (Sysmon Event ID 11) with process creation linking downloaded tools to the downloading process; and authentication events (Event ID 4624) with ShellBags/UserAssist linking logon sessions to specific attacker activities."),
("Forensic Investigation","qa",["event_4672","special_privileges"],P,"How is Event ID 4672 (Special Privileges Assigned to New Logon) useful for ransomware investigation?","Event ID 4672 is generated when an account logs on with special privileges (administrative privileges). It records: the account name, domain, logon ID (correlates with 4624), and the list of privileges assigned. For ransomware investigation: identify privileged logon sessions used by the attacker by filtering for 4672 events during the attack window with accounts known to be compromised; track which accounts had SeDebugPrivilege (required for LSASS access and process injection), SeBackupPrivilege and SeRestorePrivilege (allows reading any file regardless of ACLs), SeTakeOwnershipPrivilege (allows taking ownership of any object), and SeImpersonatePrivilege (required for token impersonation attacks like potato exploits). Cross-reference the LogonID field with Event ID 4624 to determine the source system, logon type, and authentication protocol for each privileged session. Alert on: 4672 events for service accounts with interactive logon types (service accounts should not generate interactive privileged sessions); 4672 events at unusual times for administrative accounts; and 4672 events from workstation-class systems for Tier 0 accounts (violating tiered administration)."),
("Prevention Best Practices","qa",["incident_playbook","soc_procedures"],P,"What should a SOC playbook for ransomware precursor alerts include?","A ransomware precursor playbook guides analyst response to alerts that indicate an active intrusion before encryption. Alert categories and responses: (1) Credential theft (LSASS access, Kerberoasting): CRITICAL - immediately isolate the source system via EDR; check for lateral movement from that system within the last 24 hours; escalate to IR team. (2) Lateral movement (PsExec, remote scheduled task): HIGH - identify the source and destination systems; check if the account used is compromised; isolate both systems pending investigation. (3) Reconnaissance (BloodHound, AdFind, network scanning): MEDIUM - confirm the tool is not authorized IT activity; check the executing account and system for compromise indicators; monitor for follow-on credential theft. (4) Defense evasion (AV disabled, driver installation): CRITICAL - isolate the system immediately; check all systems for similar disabling activity (may indicate domain-wide GPO change); verify EDR agent status across the fleet. (5) Data staging (WinRAR compression, Rclone installation): HIGH - identify what data is being staged; check for exfiltration activity to external destinations; consider network-level containment of the source system. Each playbook entry should include: triage questions, containment authority level, escalation criteria, evidence collection steps, and communication requirements."),
("Forensic Investigation","qa",["hiberfil_analysis","memory_recovery"],P,"How can the Windows hibernation file (hiberfil.sys) aid ransomware forensic investigation?","The hibernation file (C:\\hiberfil.sys) contains a compressed copy of system memory from when the system last entered hibernation or was using hybrid sleep. Forensic value: it may contain complete process memory including encryption keys from ransomware that was running when the system hibernated; Cobalt Strike beacon configurations and C2 addresses; LSASS process memory with cached credentials; network connection state information; and user session data including clipboard contents. Analysis: decompress hiberfil.sys using Volatility's windows.hibernation plugin or Comae's toolkit; once decompressed, analyze using standard memory forensics techniques (Volatility 3 plugins). Key consideration: hiberfil.sys from before the ransomware attack may contain pre-encryption system state, potentially including original file contents in memory buffers. Collection: hiberfil.sys is a system file that requires raw disk access to copy; use FTK Imager or KAPE to collect it during triage. On systems using Fast Startup (default in Windows 10/11), hiberfil.sys is written at every shutdown, making it a frequently updated memory snapshot."),
("Prevention Best Practices","qa",["network_detection","ids_ips"],P,"What IDS/IPS signatures are most effective for detecting ransomware-related network activity?","Priority IDS/IPS signatures for ransomware detection include: Cobalt Strike signatures matching default and common malleable C2 profiles (ET OPEN rules provide comprehensive coverage); PsExec network signatures detecting remote service creation over SMB; Mimikatz network indicators including DRSUAPI/DCSync patterns over RPC; lateral movement patterns: anomalous SMB session setups between workstations, remote scheduled task creation over RPC, and WMI remote execution traffic; exfiltration indicators: connections to known cloud storage APIs (Mega, pCloud) from internal systems, high-volume outbound transfers during off-hours; and exploit signatures for common ransomware entry points (ProxyShell, ProxyLogon, Fortinet, Ivanti exploitation patterns). Deployment: position IDS sensors at: internet egress points (detect C2 and exfiltration), between network segments (detect lateral movement), and in front of critical assets (detect targeted access to DCs, backup infrastructure). Use Suricata or Zeek for open-source IDS with regularly updated Emerging Threats rulesets. Complement signature-based detection with anomaly detection for encrypted traffic analysis."),
("Prevention Best Practices","qa",["gpo_security","group_policy_hardening"],P,"What Group Policy misconfigurations do ransomware operators commonly exploit?","Ransomware operators exploit several common GPO misconfigurations. Group Policy Preferences credentials: GPP passwords stored in SYSVOL (MS14-025) can be decrypted by any authenticated user using gpp-decrypt; audit SYSVOL for any remaining GPP XML files containing cpassword attributes. Weak GPO permissions: non-admin users or groups with edit rights on GPOs can modify policies to deploy ransomware domain-wide; audit all GPO ACLs using Get-GPOReport and check for unexpected write permissions. Logon scripts in SYSVOL: attackers can modify existing logon scripts to include ransomware deployment commands; monitor SYSVOL\\<domain>\\scripts\\ for unauthorized modifications. GPO-based software deployment: unrestricted software installation via GPO can be abused for payload delivery; restrict who can create and link GPOs to OUs containing servers and workstations. Unrestricted PowerShell execution: GPOs that set ExecutionPolicy to Unrestricted or Bypass enable script-based attacks; enforce Constrained Language Mode instead. Disabled Windows Firewall: GPOs that disable Windows Firewall on all systems remove host-level lateral movement barriers; implement firewall policies that restrict inbound connections while maintaining firewall enforcement."),
    ]
    for s,e,t,p,q,a in D:
        R.append(mk(S,U,s,e,t,p,q,a))
    return R


